option.value:
@echo off echo Configurando datos de OSRM para Argentina...
set OSRM_DATA_DIR=%~dp0..\osrm-data set TEMP_DIR=%TEMP%\osrm-setup
:: Crear directorios if not exist "%OSRM_DATA_DIR%" mkdir "%OSRM_DATA_DIR%" if not exist "%TEMP_DIR%" mkdir "%TEMP_DIR%"
echo Descargando mapa de Argentina desde Geofabrik... echo Esto puede tomar varios minutos dependiendo de la conexión...
:: Descargar el archivo OSM de Argentina curl -L -o "%TEMP_DIR%\argentina-latest.osm.pbf" "https://download.geofabrik.de/south-america/argentina-latest.osm.pbf"
if %ERRORLEVEL% neq 0 ( echo Error: No se pudo descargar el archivo OSM de Argentina echo Verifica tu conexión a internet e intenta nuevamente pause exit /b 1 )
echo Archivo descargado exitosamente. echo Procesando datos con OSRM (esto puede tomar bastante tiempo)...
:: Usar Docker para procesar los datos docker run -t -v "%OSRM_DATA_DIR%":/data -v "%TEMP_DIR%":/temp ghcr.io/project-osrm/osrm-backend osrm-extract -p /opt/car.lua /temp/argentina-latest.osm.pbf --output /data/argentina-latest.osrm
if %ERRORLEVEL% neq 0 ( echo Error: Fallo en osrm-extract pause exit /b 1 )
docker run -t -v "%OSRM_DATA_DIR%":/data ghcr.io/project-osrm/osrm-backend osrm-partition /data/argentina-latest.osrm
if %ERRORLEVEL% neq 0 ( echo Error: Fallo en osrm-partition pause exit /b 1 )
docker run -t -v "%OSRM_DATA_DIR%":/data ghcr.io/project-osrm/osrm-backend osrm-customize /data/argentina-latest.osrm
if %ERRORLEVEL% neq 0 ( echo Error: Fallo en osrm-customize pause exit /b 1 )
:: Limpiar archivos temporales rmdir /s /q "%TEMP_DIR%"
echo. echo ¡Configuración de OSRM completada exitosamente! echo Los datos de Argentina están listos para usar. echo. pause
